export function initialize(dotNetRef, timeoutMs) {
    let timer = null;
    let isIdle = false;

    const events = ["mousemove", "keydown", "click", "scroll", "touchstart"];

    function resetTimer() {
        clearTimeout(timer);

        if (isIdle) {
            isIdle = false;
            dotNetRef.invokeMethodAsync("OnUserActive");
        }

        timer = setTimeout(() => {
            isIdle = true;
            dotNetRef.invokeMethodAsync("OnUserIdle");
        }, timeoutMs);
    }

    events.forEach(e => document.addEventListener(e, resetTimer, { passive: true }));

    // Start the initial idle countdown
    resetTimer();

    return {
        dispose() {
            clearTimeout(timer);
            events.forEach(e => document.removeEventListener(e, resetTimer));
        },
        updateTimeout(newTimeoutMs) {
            timeoutMs = newTimeoutMs;
            resetTimer();
        }
    };
}

